var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>유기체 감지. 바이탈 체크 실행.</color>","JPN":"<color=#ff3636>有機体感知 バイタルチェック実行。</color>","ENG":"<color=#ff3636>Organic beings detected. Checking vital signs.</color>","TWN":"<color=#ff3636>感應到生物體。執行生命跡象確認。</color>"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"저건…… 침식체? 아니, 퓨처 앳 워에서 만든 기계 아냐?","JPN":"あれは……侵食体？　いや、フューチャーアットウォーで作った機械じゃないか？","ENG":"Is that... a C.O.? Or a machine made by Future-at-War?","TWN":"那是… 侵蝕體？不，不是天啟兵器製造的機械嗎？"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"글쎄요? 저희 편의점은 별별 물건을 다 취급하지만 저 로봇은 없는데요?","JPN":"さあ、うちのコンビニでは色んな物を扱っていますけど、あのロボットはないですよ？","ENG":"Hm? Our convenience store has many things, but not that robot.","TWN":"這個嘛？我們便利店雖然販賣各式各樣的東西，但好像沒有那個機器人？"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"조, 좋아. 뭐가 됐든 이 린 시엔님의 대활약을 다시 이어나갈 때가 온 것 같군.","JPN":"まぁ、いいか。何であれ、このリン・シエン様の大活躍を再び見せる時が来たようだな。","ENG":"O-okay, I guess it’s time for Lin Xien in action again.","TWN":"好…好吧。總之又到我大展身手的時候囉！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"물러나세요, 시엔 씨. 객기로 상대할 적이 아닙니다.","JPN":"下がってください、シエンさん。ノリで相手できる敵ではありません。","ENG":"Stay back, Xien. That thing is not to be toyed with.","TWN":"西恩，退下吧。現在不是意氣用事的時候。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"엥? 어, 왜?","JPN":"え？　なんで？","ENG":"Hm? Um, why?","TWN":"嗯？為什麼？"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"저 기계의 통칭은 모더레이터. 위험도로 평가하면 4종 침식체에 준하는 파괴 병기입니다.","JPN":"あの機械は通称モデレーター。危険度で評価すると第4種侵食体に準ずる破壊兵器です。","ENG":"That is the Moderator. It’s a destructive weapon with a danger level equivalent to a Category 4 C.O.","TWN":"那個機器統稱為仲裁者。是危險程度當於4類侵蝕體的破壞性武器。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"4종이요? 그렇지만 저건……?","JPN":"第4種ですか？　でもあれは……？","ENG":"Category 4? But it’s...","TWN":"4類？可是…？"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"……훗. 훗훗. 아쉽군. 배를 내놓고 너무 질주했더니 속이 쓰려 오네.","JPN":"……フッフッフッ。残念だな。お腹を出した状態で走りすぎたせいか、お腹が痛くなってきたぞ。","ENG":"...Hah, hah hah. This is regretful. I’ve been exposing my belly for too long, now I’m having a stomachache.","TWN":"…呵呵，真是不湊巧。剛剛騎車時肚子吹到風，現在肚子有點不舒服！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"이 린 시엔님이 만전의 상태였다면 좋은 승부를 낼 수 있었을 텐데!","JPN":"このリン・シエン様が万全の状態だったらイイ勝負ができたはずなのに！","ENG":"I would have been able to fight it if it wasn’t for this stomachache!","TWN":"要不是我肚子痛，肯定三兩下就打爆它們的！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>바이탈 체크 완료. 침식 증후군 증상 확인 불가.</color>","JPN":"<color=#ff3636>バイタルチェック完了。侵食症候群の症状確認不可。</color>","ENG":"<color=#ff3636>Vital signs checked. Unable to verify Corruption Syndrome symptoms.</color>","TWN":"<color=#ff3636>生命跡象確認完畢。無法確認侵蝕症候群。</color>"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>침식 위험성 ─── &*#&퍼센트. 소각 필요.</color>","JPN":"<color=#ff3636>侵食危険性 ─── &*#&パーセント。焼却必要。</color>","ENG":"<color=#ff3636>The chances of Corruption ─── &*#& percent. Incineration required.</color>","TWN":"<color=#ff3636>侵蝕危險性 ─── &*#&%。需要燒毀。</color>"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"다른 태스크포스들에게 맡기고 싶지만, 관리국이 발령한 적색 긴급 방어령을 받고 오려면 한세월씩 걸리겠죠.","JPN":"他のタスクフォースカンパニーに任せたいのですが、管理局が発令したパターンレッドの緊急防御令を受けてから来るには間に合いません。","ENG":"I wish there were other TASKFORCE companies to take care of it, but it will be too late if we wait until the Administration issues the red alert and finds someone for the job.","TWN":"雖然想交給其他特遣勢力，但等到管理局發布紅色緊急防備令，需要一個多月的時間吧？"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"무기만 있으면 됩니다. 물론 준비하셨겠죠?","JPN":"武器さえあれば問題ないです。もちろん準備できていますよね？","ENG":"All I need is my weapon. Of course you got it ready, didn’t you?","TWN":"只要劍在手就沒問題，有帶來吧？"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"당연하지! 만약을 대비해 예거 양에게 부탁했다네!","JPN":"当然さ！　念のためイェーガーさんに頼んである。","ENG":"Of course! I asked Ms. Jaegar to bring it just in case.","TWN":"當然囉！以防萬一，我早就拜託拉拉囉！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자, 라라 양? 주문했던 물건을 받을 수 있겠나?","JPN":"さあ、イェーガーさん。注文した物を渡してくれ。","ENG":"Lara, may I have the package I requested?","TWN":"拉拉？我訂的東西沒問題吧？"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"아 참, 내 정신 좀 봐! 하마터면 정시 배달을 못 했겠어요!","JPN":"あ、そうだ！　うっかりしていました！","ENG":"Oh my! I almost missed the on-time delivery!","TWN":"對吼，我真是的！差點無法準時送達！"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};